import { Kernel } from '@semantic-kernel/core';

const validatePlan = (plan: string, kernel: Kernel): boolean => {
  const availableFunctions = kernel.functions.listFunctions();
  const planFunctions = plan.match(/{{\s*\w+\s*}}/g) || [];

  return planFunctions.every(planFunc => 
    availableFunctions.some(func => 
      func.name === planFunc.replace(/[{}]/g, '')
    )
  );
};

// Usage
kernel.planner.createPlan('...').then(plan => {
  if (!validatePlan(plan, kernel)) {
    console.error('Invalid execution plan detected');
  }
});
