from semantic_kernel import KernelFunction
from functools import wraps

def circuit_breaker(max_errors: int = 2):
    errors = 0
    @wraps
    def wrapper(func: KernelFunction):
        def invoke(*args, **kwargs):
            nonlocal errors
            try:
                result = func.invoke(*args, **kwargs)
                errors = 0
                return result
            except Exception:
                errors += 1
                if errors >= max_errors:
                    raise Exception('Circuit breaker tripped')
        return invoke
    return wrapper

# Apply to risky plugins
risky_plugin = circuit_breaker()(original_plugin)
