import { Plan } from '@semantic-kernel/planner';

const safePlanner = {
  createPlan: async (goal: string, kernel: Kernel): Promise<Plan> => {
    const plan = await kernel.planner.createPlan(goal);

    // Validate all steps
    for (const step of plan.steps) {
      const func = kernel.functions.getFunction(step.pluginName, step.functionName);
      if (!func) {
        throw new Error(`Invalid plan step: ${step.functionName}`);
      }
    }

    return plan;
  }
};
