from semantic_kernel.contents import ChatHistory
from typing import Dict, Any

class IsolatedPluginContext:
    def __init__(self):
        self.contexts: Dict[str, ChatHistory] = {}

    def get_context(self, plugin_name: str) -> ChatHistory:
        if plugin_name not in self.contexts:
            self.contexts[plugin_name] = ChatHistory()
        return self.contexts[plugin_name]

# Usage
